26	impl Config {
27	    pub fn validate_model_paths(&self) -> Result<()> {
28	        if self.stt.enabled {
29	            let model_path = self
30	                .stt
31	                .model_path
32	                .as_ref()
33	                .context("stt.enabled is true but stt.model_path is not set")?;
34	            ensure_file_exists(model_path, "stt.model_path")?;
35	        }
36	
37	        if self.wake.enabled {
38	            let required = [
39	                (self.wake.encoder.as_ref(), "wake.encoder"),
40	                (self.wake.decoder.as_ref(), "wake.decoder"),
41	                (self.wake.joiner.as_ref(), "wake.joiner"),
42	                (self.wake.tokens.as_ref(), "wake.tokens"),
43	                (self.wake.keywords.as_ref(), "wake.keywords"),
44	            ];
45	
46	            for (path, field) in required {
47	                let path = path.with_context(|| format!("{field} is required when wake.enabled is true"))?;
48	                ensure_file_exists(path, field)?;
49	            }
50	        }
51	
52	        Ok(())
53	    }
54	}
55	
56	fn ensure_file_exists(path: &PathBuf, field: &str) -> Result<()> {
57	    std::fs::metadata(path).with_context(|| {
58	        format!(
59	            "{field} points to a missing file: {}\n\
60	             Provide a valid local path (no downloads are performed automatically).",
61	            path.display()
62	        )
63	    })?;
64	    Ok(())
65	}
