258	/// Return the XDG config file path (D-14).
259	/// $XDG_CONFIG_HOME/vibe-attack/config.yaml, or ~/.config/vibe-attack/config.yaml.
260	/// Return the XDG config file path (D-14), creating the config directory if needed.
261	/// $XDG_CONFIG_HOME/vibe-attack/config.yaml, or ~/.config/vibe-attack/config.yaml.
262	pub fn default_config_path() -> Result<PathBuf> {
263	    let xdg = xdg::BaseDirectories::with_prefix("vibe-attack");
264	    xdg.place_config_file("config.yaml")
265	        .context("Failed to create XDG config directory for vibe-attack")
266	}
