268	/// Load and deserialize config from the given path (or XDG default).
269	/// Returns Err with an actionable message on any parse or I/O failure.
270	pub fn load(path_override: Option<&std::path::Path>) -> Result<Config> {
271	    let path = match path_override {
272	        Some(p) => p.to_path_buf(),
273	        None => default_config_path()?,
274	    };
275	
276	    let file = std::fs::File::open(&path).with_context(|| {
277	        format!(
278	            "Config file not found: {}\n\
279	             Create it at that path. See config.example.yaml for the format.",
280	            path.display()
281	        )
282	    })?;
283	
284	    let config: Config = serde_yaml_ng::from_reader(file).with_context(|| {
285	        format!("Failed to parse config file: {}", path.display())
286	    })?;
287	
288	    Ok(config)
289	}
