18	pub struct DispatcherState {
19	    pub flags: Arc<RwLock<HashMap<String, bool>>>,
20	}
21	
22	impl Default for DispatcherState {
23	    fn default() -> Self {
24	        Self::new()
25	    }
26	}
27	
28	impl DispatcherState {
29	    pub fn new() -> Self {
30	        Self {
31	            flags: Arc::new(RwLock::new(HashMap::new())),
32	        }
33	    }
34	
35	    pub fn get(&self, flag: &str) -> bool {
36	        *self.flags.read().unwrap().get(flag).unwrap_or(&false)
37	    }
38	
39	    pub fn set(&self, flag: &str, value: bool) {
40	        self.flags.write().unwrap().insert(flag.to_string(), value);
41	    }
42	}
43	
44	pub struct Dispatcher {
45	    state: DispatcherState,
46	    matcher: PhraseMatcher,
47	    macros: Arc<RwLock<Vec<MacroConfig>>>,
48	    sound_player: Option<SoundPlayer>,
49	    macro_tx: Sender<MacroCmd>,
50	    default_dwell_ms: u64,
51	    default_gap_ms: u64,
52	}
53	
54	// Dispatcher is safe to send between threads since all its fields are either Send or Arc-wrapped
55	unsafe impl Send for Dispatcher {}
56	unsafe impl Sync for Dispatcher {}
57	
58	impl Dispatcher {
59	    pub fn new(
60	        threshold: f32,
61	        macros: Vec<MacroConfig>,
62	        macro_tx: Sender<MacroCmd>,
63	        default_dwell_ms: u64,
64	        default_gap_ms: u64,
65	    ) -> Self {
66	        let sound_player = match SoundPlayer::new() {
67	            Ok(player) => Some(player),
68	            Err(e) => {
69	                tracing::warn!("Sound player disabled: {}", e);
70	                None
71	            }
72	        };
73	
74	        Self {
75	            state: DispatcherState::new(),
76	            matcher: PhraseMatcher::new(threshold),
77	            macros: Arc::new(RwLock::new(macros)),
78	            sound_player,
79	            macro_tx,
80	            default_dwell_ms,
81	            default_gap_ms,
82	        }
83	    }
84	
85	    pub fn update_macros(&self, new_macros: Vec<MacroConfig>) {
86	        let mut macros = self.macros.write().unwrap();
87	        *macros = new_macros;
88	        tracing::info!("Registry updated with {} macros", macros.len());
89	    }
90	
91	    pub fn macro_count(&self) -> usize {
92	        self.macros.read().unwrap().len()
93	    }
94	
95	    fn check_condition(&self, if_flag: &Option<String>) -> bool {
96	        match if_flag {
97	            None => true,
98	            Some(if_flag) => {
99	                if let Some(stripped) = if_flag.strip_prefix('!') {
100	                    !self.state.get(stripped)
101	                } else {
102	                    self.state.get(if_flag.as_str())
103	                }
104	            }
105	        }
106	    }
107	
108	    pub fn process(&self, transcript: &str) -> DispatchOutcome {
109	        let macros = self.macros.read().unwrap();
110	        let candidates = macros
111	            .iter()
112	            .filter(|m| self.check_condition(&m.if_flag))
113	            .filter_map(|m| m.phrase.as_ref().map(|p| (m.name.as_str(), p.as_str())));
114	
115	        if let Some((best_match_name, score)) = self.matcher.find_best_match(transcript, candidates) {
116	            tracing::info!(macro_name = best_match_name, score, "Firing macro");
117	            if let Some(mac) = macros.iter().find(|m| m.name == best_match_name) {
118	                if let Some(sound_path) = &mac.sound {
119	                    if let Some(player) = &self.sound_player {
120	                        if let Err(e) = player.play(sound_path) {
121	                            tracing::error!("Failed to play sound for macro {}: {}", mac.name, e);
122	                        }
123	                    }
124	                }
125	
126	                let keys = mac.keys.iter().map(KeyStep::from_config).collect();
127	                let _ = self.macro_tx.send(MacroCmd::Execute {
128	                    keys,
129	                    default_dwell_ms: self.default_dwell_ms,
130	                    default_gap_ms: self.default_gap_ms,
131	                });
132	
133	                if let Some(set_flag) = &mac.set_flag {
134	                    if let Some(stripped) = set_flag.strip_prefix('!') {
135	                        self.state.set(stripped, false);
136	                    } else {
137	                        self.state.set(set_flag.as_str(), true);
138	                    }
139	                }
140	
141	                return DispatchOutcome::Fired {
142	                    macro_id: best_match_name.to_string(),
143	                    score,
144	                };
145	            }
146	        }
147	
148	        tracing::debug!(transcript, "No phrase matched above threshold");
149	        DispatchOutcome::NoMatch
150	    }
151	}
