3	/// Capture wall-clock time as unix milliseconds (D-21).
4	///
5	/// Chosen over RFC3339 to avoid extra dependencies; the contract allows either.
6	pub fn wall_time_ms() -> u64 {
7	    let d = SystemTime::now()
8	        .duration_since(UNIX_EPOCH)
9	        .unwrap_or(Duration::from_secs(0));
10	    d.as_millis() as u64
11	}
