19	impl MonoClock {
20	    pub fn start_now() -> Self {
21	        Self {
22	            start: Instant::now(),
23	        }
24	    }
25	
26	    pub fn elapsed(&self) -> Duration {
27	        self.start.elapsed()
28	    }
29	
30	    pub fn elapsed_ms(&self) -> u64 {
31	        self.elapsed().as_millis() as u64
32	    }
33	}
