56	impl UtteranceTimings {
57	    pub fn new() -> Self {
58	        Self {
59	            created_wall_time_ms: wall_time_ms(),
60	            created_instant: Instant::now(),
61	            vad_done_ms: None,
62	            vad_ms: 0,
63	            stt_done_ms: None,
64	            output_done_ms: None,
65	        }
66	    }
67	
68	    pub fn elapsed_ms(&self) -> u64 {
69	        self.created_instant.elapsed().as_millis() as u64
70	    }
71	
72	    pub fn mark_vad_done(&mut self) {
73	        self.vad_done_ms = Some(self.elapsed_ms());
