1	use strsim::levenshtein;
2	
3	pub struct PhraseMatcher {
4	    threshold: f32,
5	}
6	
7	impl PhraseMatcher {
8	    pub fn new(threshold: f32) -> Self {
9	        Self { threshold }
10	    }
11	
12	    pub fn normalize(input: &str) -> String {
13	        input
14	            .to_lowercase()
15	            .trim()
16	            .chars()
17	            .filter(|c| c.is_alphanumeric() || c.is_whitespace())
18	            .collect::<String>()
19	            .split_whitespace()
20	            .collect::<Vec<_>>()
21	            .join(" ")
22	    }
23	
24	    pub fn find_best_match<'a>(
25	        &self,
26	        input: &str,
27	        candidates: impl Iterator<Item = (&'a str, &'a str)>,
28	    ) -> Option<(&'a str, f32)> {
29	        let norm_input = Self::normalize(input);
30	        if norm_input.is_empty() {
31	            return None;
32	        }
33	
34	        let mut best_match = None;
35	        let mut best_score = 0.0;
36	
37	        for (id, phrase) in candidates {
38	            let norm_phrase = Self::normalize(phrase);
39	            if norm_phrase.is_empty() {
40	                continue;
41	            }
42	
43	            let max_len = norm_input.chars().count().max(norm_phrase.chars().count()) as f32;
44	            let dist = levenshtein(&norm_input, &norm_phrase) as f32;
45	            let score = if max_len > 0.0 {
46	                1.0 - (dist / max_len)
47	            } else {
48	                0.0
49	            };
50	
51	            if score >= self.threshold && score > best_score {
52	                best_score = score;
53	                best_match = Some((id, score));
54	            }
55	        }
56	
57	        best_match
58	    }
59	}
60	
61	#[cfg(test)]
62	mod tests {
63	    use super::*;
64	
65	    #[test]
66	    fn test_normalize() {
67	        assert_eq!(PhraseMatcher::normalize("Hello, World!"), "hello world");
68	        assert_eq!(PhraseMatcher::normalize("  eagle   airstrike...  "), "eagle airstrike");
69	    }
70	
71	    #[test]
72	    fn test_exact_match() {
73	        let matcher = PhraseMatcher::new(0.8);
74	        let candidates = vec![("macro1", "eagle airstrike")];
75	        let matched = matcher.find_best_match("eagle airstrike", candidates.into_iter());
76	        assert_eq!(matched.unwrap().0, "macro1");
77	        assert_eq!(matched.unwrap().1, 1.0);
78	    }
79	
80	    #[test]
81	    fn test_fuzzy_match() {
82	        let matcher = PhraseMatcher::new(0.8);
83	        let candidates = vec![("macro1", "eagle airstrike")];
84	        // "eagal airstrike" has levenshtein distance of 1 from "eagle airstrike"
85	        let matched = matcher.find_best_match("eagal airstrike", candidates.into_iter());
86	        assert!(matched.is_some());
87	        assert_eq!(matched.unwrap().0, "macro1");
88	    }
89	
90	    #[test]
91	    fn test_threshold_rejection() {
92	        let matcher = PhraseMatcher::new(0.8);
93	        let candidates = vec![("macro1", "eagle airstrike")];
94	        let matched = matcher.find_best_match("orbital strike", candidates.into_iter());
95	        assert!(matched.is_none());
96	    }
97	
98	    #[test]
