65	/// Spawn the control channel listener on a Tokio task.
66	///
67	/// Listens on a Unix Domain Socket for commands from the CLI.
68	pub async fn spawn_control_listener(handle: DaemonHandle) -> Result<()> {
69	    let socket_path = get_socket_path()?;
70	
71	    // Clean up existing socket file if it exists
72	    if socket_path.exists() {
73	        std::fs::remove_file(&socket_path)
74	            .with_context(|| format!("Failed to remove existing socket: {}", socket_path.display()))?;
75	    }
76	
77	    let listener = UnixListener::bind(&socket_path)
78	        .with_context(|| format!("Failed to bind to UDS socket: {}", socket_path.display()))?;
79	
80	    // Set permissions to 0600 (user only)
81	    #[cfg(unix)]
82	    {
83	        use std::os::unix::fs::PermissionsExt;
84	        std::fs::set_permissions(&socket_path, std::fs::Permissions::from_mode(0o600))?;
85	    }
86	
87	    tracing::info!("Control channel listening on: {}", socket_path.display());
88	
89	    tokio::spawn(async move {
90	        loop {
91	            match listener.accept().await {
92	                Ok((mut stream, _)) => {
93	                    let h = handle.clone();
94	                    tokio::spawn(async move {
95	                        let (reader, mut writer) = stream.split();
96	                        let mut reader = BufReader::new(reader);
97	                        let mut line = String::new();
98	
99	                        if let Ok(n) = reader.read_line(&mut line).await {
100	                            if n == 0 { return; }
101	
102	                            let response = match serde_json::from_str::<ControlRequest>(&line) {
103	                                Ok(req) => {
104	                                    tracing::debug!("Control request: {:?}", req);
105	                                    match req {
106	                                        ControlRequest::Ping => ControlResponse::Pong,
107	                                        ControlRequest::Status => {
108	                                            ControlResponse::StatusData(h.status())
109	                                        }
110	                                        ControlRequest::Mute => {
111	                                            h.muted.store(true, Ordering::Relaxed);
112	                                            tracing::info!("Daemon muted via control socket");
113	                                            ControlResponse::Ok
114	                                        }
115	                                        ControlRequest::Unmute => {
116	                                            h.muted.store(false, Ordering::Relaxed);
117	                                            tracing::info!("Daemon unmuted via control socket");
118	                                            ControlResponse::Ok
119	                                        }
120	                                        ControlRequest::SwitchProfile { name } => {
121	                                            match tokio::task::block_in_place(|| {
122	                                                handle_switch_profile(&name, &h)
123	                                            }) {
124	                                                Ok(_) => ControlResponse::Ok,
125	                                                Err(e) => ControlResponse::Error { message: e.to_string() },
126	                                            }
127	                                        }
128	                                        ControlRequest::Shutdown => {
129	                                            // TODO: wire to CancellationToken in a future slice
130	                                            ControlResponse::Ok
131	                                        }
132	                                        _ => ControlResponse::Error { message: "Not yet implemented".into() },
133	                                    }
134	                                }
135	                                Err(e) => ControlResponse::Error { message: format!("Invalid JSON: {e}") },
136	                            };
137	
138	                            if let Ok(resp_json) = serde_json::to_string(&response) {
139	                                let _ = writer.write_all(resp_json.as_bytes()).await;
140	                                let _ = writer.write_all(b"\n").await;
141	                            }
142	                        }
143	                    });
144	                }
145	                Err(e) => {
146	                    tracing::error!("Control listener accept error: {e}");
147	                }
148	            }
149	        }
150	    });
151	
152	    Ok(())
153	}
154	
155	fn handle_switch_profile(name: &str, handle: &DaemonHandle) -> Result<()> {
156	    use crate::pack::Pack;
157	    use crate::pack::manager::ProfileManager;
158	
159	    let dir = crate::pack::get_profiles_dir()?.join(name);
160	    let pack = Pack::load_from_dir(&dir)?;
161	    handle.dispatcher.update_macros(pack.flatten());
162	
163	    // Track active profile for status queries
164	    *handle.active_profile.write().unwrap() = Some(name.to_string());
165	
166	    // Update persistence so it survives restart
167	    let mut manager = ProfileManager::load().unwrap_or(ProfileManager { active_profile: None });
168	    manager.active_profile = Some(name.to_string());
169	    manager.save()?;
170	
171	    Ok(())
172	}
